parameters.query:
SELECT * FROM public.fn_upsert_usuario_perfil(
  '{{ String($('When Executed by Another Workflow').first().json.telefono || '').replace(/'/g, "''") }}',
  {{ (() => { const v = String($('When Executed by Another Workflow').first().json.nombre || '').trim(); return v ? "'" + v.replace(/'/g, "''") + "'" : 'NULL'; })() }},
  {{ (() => { const v = String($('When Executed by Another Workflow').first().json.direccion || '').trim(); return v ? "'" + v.replace(/'/g, "''") + "'" : 'NULL'; })() }},
  {{ (() => { const v = String($('When Executed by Another Workflow').first().json.tipo_despacho || '').trim(); return v ? "'" + v.replace(/'/g, "''") + "'" : 'NULL'; })() }}
)

parameters.jsCode:
const row = $json || {};
const trigger = $('When Executed by Another Workflow').first().json || {};
const nombre = row.nombre || trigger.nombre || null;
const direccion = row.direccion_frecuente || trigger.direccion || null;
let respuesta = 'Perfil actualizado.';
if (nombre && direccion && ['delivery','domicilio'].includes(String(trigger.tipo_despacho || '').toLowerCase())) respuesta = `Perfecto, lo dejo a nombre de ${nombre} y guardo esta dirección para futuras entregas.`;
else if (nombre) respuesta = `Perfecto, lo dejo a nombre de ${nombre}.`;
else if (direccion) respuesta = 'Perfecto, guardo esta dirección para futuras entregas.';
return [{json:{success:true,respuesta_agente:respuesta,id:row.id || null,nombre,direccion_frecuente:direccion,updated_name:row.updated_name || false,updated_address:row.updated_address || false}}];

// Catch global de errores para Perfil Cliente
const err = $input.first();
const origen = err?.json?.node || err?.json?.source || 'nodo desconocido';
const detalle = err?.json?.message || err?.json?.error || 'sin detalle';

return [{
  json: {
    success: false,
    error: true,
    tipo: 'sistema',
    subflujo: 'Perfil Cliente',
    mensaje: `Error técnico en Perfil Cliente (${origen}): ${detalle}`,
    puede_continuar: false
  }
}];
